import React from 'react';
import { NavLink } from 'react-router-dom';
import './AdminSidebar.css';

const AdminSidebar = () => {
  const menuItems = [
    { path: '/admin', label: 'Панель управления', icon: 'fa-tachometer-alt' },
    { path: '/admin/upload', label: 'Загрузка контента', icon: 'fa-upload' },
    { path: '/admin/analytics', label: 'Аналитика', icon: 'fa-chart-line' },
    { path: '/admin/users', label: 'Управление пользователями', icon: 'fa-users' },
    { path: '/admin/content', label: 'Управление контентом', icon: 'fa-book' },
    { path: '/admin/comments', label: 'Модерация комментариев', icon: 'fa-comments' },
    { path: '/admin/settings', label: 'Настройки', icon: 'fa-cog' }
  ];

  return (
    <div className="admin-sidebar">
      <div className="sidebar-header">
        <h3>
          <i className="fas fa-user-shield"></i>
          Админ-панель
        </h3>
      </div>
      
      <nav className="sidebar-menu">
        {menuItems.map(item => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) => 
              `menu-item ${isActive ? 'active' : ''}`
            }
          >
            <i className={`fas ${item.icon}`}></i>
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>
      
      <div className="sidebar-footer">
        <div className="admin-stats">
          <div className="stat">
            <span className="stat-label">Пользователей онлайн</span>
            <span className="stat-value">1,245</span>
          </div>
          <div className="stat">
            <span className="stat-label">Новых за сегодня</span>
            <span className="stat-value">89</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminSidebar;
